### Application-Level Instrumentation

```java
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Timer;
import java.lang.management.GarbageCollectorMXBean;
import java.lang.management.ManagementFactory;

@Component
public class GCMetricsCollector {
    private final MeterRegistry registry;
    private Map<String, Long> previousGCCounts = new ConcurrentHashMap<>();
    private Map<String, Long> previousGCTimes = new ConcurrentHashMap<>();

    @Scheduled(fixedRate = 5000) // Every 5 seconds
    public void collectGCMetrics() {
        for (GarbageCollectorMXBean gcBean : 
             ManagementFactory.getGarbageCollectorMXBeans()) {

            String gcName = gcBean.getName();
            long currentCount = gcBean.getCollectionCount();
            long currentTime = gcBean.getCollectionTime();

            long countDelta = currentCount - 
                previousGCCounts.getOrDefault(gcName, 0L);
            long timeDelta = currentTime - 
                previousGCTimes.getOrDefault(gcName, 0L);

            registry.counter("jvm.gc.count", "gc", gcName)
                .increment(countDelta);
            registry.counter("jvm.gc.time", "gc", gcName)
                .increment(timeDelta);

            previousGCCounts.put(gcName, currentCount);
            previousGCTimes.put(gcName, currentTime);
        }
    }
}
```

